import { isUndefined } from 'lodash-es';

import type { Unit } from '@dynatrace-sdk/units';

import { buildColorRangeLegendRule } from './build-color-rule.js';
import { getDataExtent } from './get-data-extent.js';
import { getRangeColoredNodes } from './get-range-colored-nodes.js';
import { getRangeLegendColorMap } from './get-range-legend-color-map.js';
import { getRangeLegendWithColorRules } from './get-range-legend-with-color-rules.js';
import type { ColorPalette } from '../../core/types/color-palette.js';
import type { ColorRuleProps } from '../../core/types/color-rule.js';
import type { ColoredRange } from '../../core/types/colored-range.js';
import type { MinMax } from '../../core/types/min-max.js';
import { buildQuantizeScaleFromColorPalette } from '../../core/utils/build-quantize-scale-from-color-palette.js';
import { buildThresholdScaleFromRanges } from '../../core/utils/build-threshold-scale-from-ranges.js';
import { isValidColorPalette } from '../../core/utils/is-valid-color-palette.js';
import {
  DEFAULT_RANGE_LEGEND_COLOR,
  DEFAULT_ROOT_NODE_NAME,
} from '../constants.js';
import {
  type ColoredInternalTreeMapData,
  type InternalTreeMapNode,
} from '../types/internal.js';

/**
 * Function to map the consumer dataset to the internal one that is sorted, colored.
 * Creates the mapping between internal data and the legend items/colors
 * @param tree -
 * @param unit -
 * @param colorPalette -
 * @param minMaxConfig -
 * @param colorRules - raw color rules to apply
 * @returns - InternalTreemapData and Coloring map
 */
export function getColoredInternalRangeData(
  tree: InternalTreeMapNode,
  colorPalette: ColorPalette | ColoredRange[],
  minMaxConfig: Partial<MinMax>,
  colorRules: ColorRuleProps[],
  unit?: string | Unit,
): ColoredInternalTreeMapData {
  const hasCustomRanges = !isValidColorPalette(colorPalette);

  let { min, max } = minMaxConfig;
  if (isUndefined(min) || isUndefined(max)) {
    const [extentMin, extentMax] = getDataExtent(tree);
    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
    min ??= extentMin!;
    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
    max ??= extentMax!;
  }

  const scale = !hasCustomRanges
    ? buildQuantizeScaleFromColorPalette(min, max, colorPalette)
    : buildThresholdScaleFromRanges(
        colorPalette as ColoredRange[],
        DEFAULT_RANGE_LEGEND_COLOR,
        minMaxConfig,
      );

  const baseLegendColorMap = getRangeLegendColorMap(
    scale,
    min,
    max,
    hasCustomRanges,
  );
  const colorRulesMap = buildColorRangeLegendRule(
    baseLegendColorMap,
    colorRules,
  );
  const legendColorMap = getRangeLegendWithColorRules(
    baseLegendColorMap,
    colorRulesMap,
  );
  const nodeArray = getRangeColoredNodes(tree, scale, min, max, colorRules);
  const rootNodeName = tree.name ?? DEFAULT_ROOT_NODE_NAME;

  const data = {
    tree: {
      ...tree,
      children: nodeArray,
      name: rootNodeName,
      id: DEFAULT_ROOT_NODE_NAME,
    },
    unit,
  };

  return { data, legendColorMap };
}
